/**
 * Plonk real verifier integration tests.
 *
 * Exercises the full cryptographic round-trip: real BN254 proof → real
 * PlonkVerifierV2 on-chain pairing check → adapter extraction → acceptance.
 *
 * Uses a proof fixture generated by:
 *   node scripts/generate-plonk-fixture.mjs
 *
 * Unlike the mock-based tests, the ecPairing precompile executes for real.
 */

import { expect } from "chai";
import { ethers, upgrades } from "hardhat";
import * as fs from "fs";
import * as path from "path";
import {
  DOMAIN,
  PROGRAM_VKEY,
  POLICY_HASH,
  MAX_ACCEPTANCE_DELAY,
  GENESIS_L2_BLOCK,
  enablePermissionless,
  findEventLog
} from "./deployment-fixtures";

interface PlonkFixture {
  publicOutputs: {
    stfCommitment: string;
    proverSetDigest: string;
  };
  proof: {
    words: string[];
  };
}

function loadFixture(): PlonkFixture {
  const fixturePath = path.join(__dirname, "../fixtures/plonk-proof-fixture.json");
  return JSON.parse(fs.readFileSync(fixturePath, "utf-8"));
}

function encodeRealPlonkProof(fixture: PlonkFixture): string {
  return ethers.AbiCoder.defaultAbiCoder().encode(
    ["uint256[24]", "uint256", "uint256"],
    [
      fixture.proof.words.map(BigInt),
      BigInt(fixture.publicOutputs.stfCommitment),
      BigInt(fixture.publicOutputs.proverSetDigest)
    ]
  );
}

function encodePublicInputsWithRealStf(
  l2Start: bigint,
  l2End: bigint,
  windowCloseTimestamp: bigint,
  realStfCommitment: string,
  domain: string = DOMAIN
): string {
  const submissionBinding = ethers.keccak256(
    ethers.AbiCoder.defaultAbiCoder().encode(
      ["uint256", "uint256", "bytes32", "bytes32", "bytes32", "uint256"],
      [l2Start, l2End, ethers.ZeroHash, ethers.ZeroHash, domain, windowCloseTimestamp]
    )
  );
  return ethers.AbiCoder.defaultAbiCoder().encode(
    ["bytes32", "uint256", "uint256", "bytes32", "bytes32", "bytes32", "uint256", "bytes32"],
    [
      realStfCommitment,
      l2Start,
      l2End,
      ethers.ZeroHash,
      ethers.ZeroHash,
      domain,
      windowCloseTimestamp,
      submissionBinding
    ]
  );
}

describe("Plonk real verifier integration", function () {
  this.timeout(120_000);

  let fixture: PlonkFixture;

  before(function () {
    fixture = loadFixture();
  });

  it("real PlonkVerifierV2 accepts a genuine BN254 proof via adapter", async function () {
    const [owner] = await ethers.getSigners();

    const Verifier = await ethers.getContractFactory("PlonkVerifierV2", owner);
    const verifier = await Verifier.deploy();
    await verifier.waitForDeployment();

    const Adapter = await ethers.getContractFactory("PlonkZkAdapter", owner);
    const adapter = await Adapter.deploy(await verifier.getAddress(), PROGRAM_VKEY, POLICY_HASH);
    await adapter.waitForDeployment();

    const envelope = encodeRealPlonkProof(fixture);
    const result = await adapter.getFunction("verify(bytes,bytes)").staticCall(envelope, "0x");

    expect(result.valid).to.equal(true, "Real verifier must accept genuine proof");
    expect(result.stfCommitment).to.equal(fixture.publicOutputs.stfCommitment);
    expect(result.proverSetDigest).to.equal(fixture.publicOutputs.proverSetDigest);
  });

  it("real PlonkVerifierV2 rejects corrupted proof via adapter", async function () {
    const [owner] = await ethers.getSigners();

    const Verifier = await ethers.getContractFactory("PlonkVerifierV2", owner);
    const verifier = await Verifier.deploy();
    await verifier.waitForDeployment();

    const Adapter = await ethers.getContractFactory("PlonkZkAdapter", owner);
    const adapter = await Adapter.deploy(await verifier.getAddress(), PROGRAM_VKEY, POLICY_HASH);
    await adapter.waitForDeployment();

    // Corrupt first proof word
    const badWords = fixture.proof.words.map(BigInt);
    badWords[0] ^= 1n;
    const envelope = ethers.AbiCoder.defaultAbiCoder().encode(
      ["uint256[24]", "uint256", "uint256"],
      [
        badWords,
        BigInt(fixture.publicOutputs.stfCommitment),
        BigInt(fixture.publicOutputs.proverSetDigest)
      ]
    );

    await expect(adapter.getFunction("verify(bytes,bytes)").staticCall(envelope, "0x")).to.be
      .reverted;
  });

  it("full stack submission with real Plonk proof through router and finalizer", async function () {
    const [owner] = await ethers.getSigners();

    // Deploy real Plonk verifier + adapter
    const Verifier = await ethers.getContractFactory("PlonkVerifierV2", owner);
    const verifier = await Verifier.deploy();
    await verifier.waitForDeployment();

    const Adapter = await ethers.getContractFactory("PlonkZkAdapter", owner);
    const adapter = await Adapter.deploy(await verifier.getAddress(), PROGRAM_VKEY, POLICY_HASH);
    await adapter.waitForDeployment();

    // Also need a Groth16 adapter for the finalizer's direct adapter slot
    const MockGroth16 = await ethers.getContractFactory("MockGroth16Verifier", owner);
    const mockG16 = await MockGroth16.deploy();
    await mockG16.waitForDeployment();
    const G16Adapter = await ethers.getContractFactory("Groth16ZkAdapter", owner);
    const g16Adapter = await G16Adapter.deploy(
      await mockG16.getAddress(),
      PROGRAM_VKEY,
      POLICY_HASH
    );
    await g16Adapter.waitForDeployment();

    // Deploy router and register Plonk adapter at ID=2
    const Router = await ethers.getContractFactory("ProofRouter", owner);
    const router = await upgrades.deployProxy(Router, [], { kind: "uups" });
    await router.waitForDeployment();
    await (await (router as any).registerAdapter(2, await adapter.getAddress())).wait();

    // Deploy finalizer
    const Finalizer = await ethers.getContractFactory("WorldlineFinalizer", owner);
    const finalizer = await upgrades.deployProxy(
      Finalizer,
      [
        await g16Adapter.getAddress(),
        DOMAIN,
        MAX_ACCEPTANCE_DELAY,
        GENESIS_L2_BLOCK,
        ethers.ZeroAddress
      ],
      { kind: "uups", initializer: "initialize" }
    );
    await finalizer.waitForDeployment();
    await (await (finalizer as any).setProofRouter(await router.getAddress())).wait();
    await enablePermissionless(finalizer);

    const l2Start = GENESIS_L2_BLOCK;
    const l2End = 100n;
    const block = await ethers.provider.getBlock("latest");
    const windowCloseTimestamp = BigInt(block!.timestamp) + 7200n;

    const proof = encodeRealPlonkProof(fixture);
    const publicInputs = encodePublicInputsWithRealStf(
      l2Start,
      l2End,
      windowCloseTimestamp,
      fixture.publicOutputs.stfCommitment,
      DOMAIN
    );

    const tx = await (finalizer as any).submitZkValidityProofRouted(2, proof, publicInputs);
    const receipt = await tx.wait();

    const event = findEventLog(receipt, (finalizer as any).interface, "ZkProofAccepted");
    expect(event).to.not.be.null;
    expect(event.args.windowIndex).to.equal(0n);
  });
});
